import React, { useState, useEffect, useCallback } from 'react';
import { AnalyzeView } from './components/AnalyzeView.tsx';
import { ReviewView } from './components/ReviewView.tsx';
import { ReportsView } from './components/ReportsView.tsx';
import { TreatmentsView } from './components/TreatmentsView.tsx';
import { SettingsView } from './components/SettingsView.tsx';
import { LoginModal } from './components/LoginModal.tsx';
import { Toast } from './components/Toast.tsx';
import { Spinner } from './components/Spinner.tsx';
import { AnimatePresence, motion } from 'framer-motion';
import { PageTransition } from './components/ui/PageTransition.tsx';
import LandingView from './components/LandingView.tsx';
import { ServicesView } from './components/ServicesView.tsx';
import { RoleSelectionView } from './components/RoleSelectionView.tsx';

import { AppLayout } from './components/layout/AppLayout.tsx';
import { useAuthSession } from './hooks/useAuthSession.ts';
import { useMedicalHistory } from './hooks/useMedicalHistory.ts';
import { useAnalysisEngine } from './hooks/useAnalysisEngine.ts';
import { useHaptic } from './hooks/useHaptic.ts';
import { useAppWorkflow } from './hooks/useAppWorkflow.ts';
import { useNavigationState } from './hooks/useNavigationState.ts';
import { AppView, AppTab, TransitionMode } from './constants/navigation.ts';

export type ToastType = 'success' | 'error' | 'info' | 'warning' | 'critical';
export type ToastItem = { id: string; message: string; type: ToastType };
type UserRole = 'guest' | 'professional' | null;

const App: React.FC = () => {
  const { appView, activeTab, transitionMode, navigateToTab, navigateToView } = useNavigationState();
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [toasts, setToasts] = useState<ToastItem[]>([]);
  const [showTreatments, setShowTreatments] = useState(true);

  const { user, isLoggedIn, login, logout, loading: authLoading } = useAuthSession();
  const medicalHistory = useMedicalHistory();
  const analysisEngine = useAnalysisEngine(isLoggedIn);
  const { triggerHaptic } = useHaptic();

  const { history, isLoadingHistory } = medicalHistory;
  const { imageFiles, imageUrls, prescriptionData, setPrescriptionData, isLoading, error, addImages, removeImage, clear, analyze } = analysisEngine;

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setToasts(prev => [...prev, { id, message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const { handleAnalyzeClick, handleSaveReview, handleVerify, handleDeleteReport } = useAppWorkflow({
      userRole,
      user,
      analysisEngine,
      medicalHistory,
      triggerHaptic,
      showToast,
      setShowLoginModal,
      navigateToTab
  });

  const handleLogout = () => {
    logout();
    setIsMenuOpen(false);
    triggerHaptic('medium');
    showToast('You have been logged out.', 'info');
    navigateToView(AppView.LANDING);
    setUserRole(null);
  };

  const handleRoleSelection = (role: UserRole) => {
    triggerHaptic('light');
    setUserRole(role);
    if (role === 'guest') {
        navigateToView(AppView.SERVICES);
    } else if (role === 'professional') {
        if (isLoggedIn) navigateToView(AppView.SERVICES);
        else setShowLoginModal(true);
    }
  };

  const displayHistory = userRole === 'guest' ? (prescriptionData ? [prescriptionData] : []) : history;

  const renderContent = () => {
    switch(activeTab) {
      case AppTab.REVIEW:
        return <ReviewView prescription={prescriptionData} imageUrls={imageUrls.length > 0 ? imageUrls : null} onSave={handleSaveReview} onVerify={handleVerify} />;
      case AppTab.REPORTS:
        return <ReportsView history={displayHistory} isLoading={isLoadingHistory} onSelectPrescription={(p) => { setPrescriptionData(p); navigateToTab(AppTab.REVIEW, TransitionMode.DRILL); }} onDeleteReport={handleDeleteReport} />;
      case AppTab.TREATMENTS:
        return <TreatmentsView prescription={prescriptionData} />;
      case AppTab.SETTINGS:
        return <SettingsView onBack={() => navigateToTab(AppTab.ANALYZE, TransitionMode.TAB)} />;
      case AppTab.ANALYZE:
      default:
        return (
          <AnalyzeView 
            imageFiles={imageFiles}
            imageUrls={imageUrls}
            prescriptionData={prescriptionData}
            isLoading={isLoading}
            error={error}
            history={displayHistory}
            onAddImages={addImages}
            onRemoveImage={removeImage}
            onClearQueue={clear}
            onAnalyze={handleAnalyzeClick}
            onVerify={() => navigateToTab(AppTab.REVIEW, TransitionMode.DRILL)}
            onSelectHistory={(item) => { setPrescriptionData(item); navigateToTab(AppTab.REVIEW, TransitionMode.DRILL); }}
            onViewAll={() => navigateToTab(AppTab.REPORTS, TransitionMode.TAB)}
            triggerHaptic={triggerHaptic}
          />
        );
    }
  };

  return (
    <div className="app-root flex flex-col min-h-screen w-full bg-light-bg dark:bg-dark-bg text-slate-900 dark:text-slate-100 transition-colors duration-300 relative overflow-x-hidden">
      <div className="fixed top-6 left-0 right-0 z-[1000] flex flex-col items-center gap-3 pointer-events-none px-4">
          <AnimatePresence>
              {toasts.map(t => (
                  <Toast key={t.id} message={t.message} type={t.type} onClose={() => removeToast(t.id)} />
              ))}
          </AnimatePresence>
      </div>

      <AnimatePresence>
        {showLoginModal && (
          <LoginModal 
            onLogin={() => {
              setShowLoginModal(false);
              setUserRole('professional');
              navigateToView(AppView.SERVICES);
            }} 
            onClose={() => setShowLoginModal(false)} 
          />
        )}
      </AnimatePresence>

      <AnimatePresence mode="wait">
        {authLoading ? (
            <motion.div key="loading" exit={{ opacity: 0 }} className="fixed inset-0 flex items-center justify-center bg-white dark:bg-black z-[500]">
                <Spinner />
            </motion.div>
        ) : (
            <React.Fragment>
                {appView === AppView.LANDING && (<motion.div key="landing" exit={{ opacity: 0, scale: 0.95 }} className="w-full h-full flex flex-col"><LandingView onStart={() => navigateToView(AppView.ROLE_SELECTION)} /></motion.div>)}
                {appView === AppView.ROLE_SELECTION && (<motion.div key="roles" exit={{ opacity: 0, scale: 0.95 }} className="w-full h-full"><RoleSelectionView onSelectRole={handleRoleSelection} onBack={() => navigateToView(AppView.LANDING)} /></motion.div>)}
                {appView === AppView.SERVICES && (<motion.div key="services" exit={{ opacity: 0, scale: 0.95 }} className="w-full h-full"><ServicesView onSelectService={(s) => { if (s === 'rx') navigateToView(AppView.APP); else showToast('Coming soon!', 'info'); }} onBack={() => navigateToView(AppView.ROLE_SELECTION)} /></motion.div>)}
                {appView === AppView.APP && (
                    <AppLayout 
                      activeTab={activeTab} 
                      setActiveTab={(t) => navigateToTab(t, TransitionMode.TAB)} 
                      isLoggedIn={isLoggedIn} 
                      isGuest={userRole === 'guest'}
                      hasData={!!prescriptionData}
                      user={user} 
                      history={displayHistory} 
                      showTreatments={showTreatments} 
                      setShowTreatments={setShowTreatments} 
                      isMenuOpen={isMenuOpen} 
                      setIsMenuOpen={setIsMenuOpen} 
                      setShowLoginModal={setShowLoginModal} 
                      showToast={showToast} 
                      onLogout={handleLogout} 
                      onLogoClick={() => navigateToView(AppView.SERVICES)} 
                      triggerHaptic={triggerHaptic}
                    >
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-grow w-full max-w-7xl mx-auto p-4 sm:p-6 lg:p-8">
                            <AnimatePresence mode="wait">
                                <PageTransition key={activeTab} mode={transitionMode}>
                                    {renderContent()}
                                </PageTransition>
                            </AnimatePresence>
                        </motion.div>
                    </AppLayout>
                )}
            </React.Fragment>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

import React from 'react';
import { HamburgerMenuIcon } from './icons/HamburgerMenuIcon.tsx';
import { AnalyzeIcon } from './icons/AnalyzeIcon.tsx';
import { ClipboardDocumentCheckIcon } from './icons/ClipboardDocumentCheckIcon.tsx';
import { FolderIcon } from './icons/FolderIcon.tsx';
import { StethoscopeIcon } from './icons/StethoscopeIcon.tsx';
import { SettingsIcon } from './icons/SettingsIcon.tsx';
import BrandLogo from './BrandLogo.tsx';
import { motion } from 'framer-motion';
import { AppTab } from '../constants/navigation.ts';

interface HeaderProps {
  activeTab: AppTab;
  setActiveTab: (tab: AppTab) => void;
  onMenuClick: () => void;
  isLoggedIn: boolean;
  isGuest: boolean;
  hasData: boolean;
  showTreatments: boolean;
  onLogoClick?: () => void;
}

export const Header: React.FC<HeaderProps> = ({ 
  activeTab, 
  setActiveTab, 
  onMenuClick, 
  isLoggedIn, 
  isGuest,
  hasData,
  showTreatments, 
  onLogoClick 
}) => {
  const navLinks: { id: AppTab; label: string; icon: React.FC<React.SVGProps<SVGSVGElement>>; color: string; bg: string }[] = [
    { id: AppTab.ANALYZE, label: 'Analyze', icon: AnalyzeIcon, color: 'text-primary', bg: 'bg-primary/5' },
    { id: AppTab.REVIEW, label: 'Review', icon: ClipboardDocumentCheckIcon, color: 'text-amber-500', bg: 'bg-amber-500/5' },
    { id: AppTab.TREATMENTS, label: 'Insights', icon: StethoscopeIcon, color: 'text-rose-500', bg: 'bg-rose-500/5' },
    { id: AppTab.REPORTS, label: 'Reports', icon: FolderIcon, color: 'text-brand-blue', bg: 'bg-brand-blue/5' },
    { id: AppTab.SETTINGS, label: 'Settings', icon: SettingsIcon, color: 'text-slate-500', bg: 'bg-slate-500/5' },
  ];

  const availableNavLinks = showTreatments ? navLinks : navLinks.filter(l => l.id !== AppTab.TREATMENTS);

  return (
    <header className="relative w-full z-40 transition-all duration-300">
      <div className="absolute inset-0 bg-white/95 dark:bg-black/90 border-b border-light-border dark:border-dark-border shadow-sm backdrop-blur-xl" />

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 sm:h-24 flex items-center justify-between">
          <div className="flex items-center cursor-pointer group" onClick={onLogoClick}>
            <BrandLogo variant="header" className="transform group-hover:scale-105 transition-transform" />
          </div>

          <div className="hidden md:flex items-center gap-1.5 bg-slate-100/50 dark:bg-white/5 p-1.5 rounded-full border border-slate-200 dark:border-white/5 backdrop-blur-md">
            {availableNavLinks.map(link => {
              const isActive = activeTab === link.id;
              const isDisabled = link.id !== AppTab.ANALYZE && link.id !== AppTab.SETTINGS && !isLoggedIn && !(isGuest && hasData);

              return (
                <button 
                  key={link.id}
                  onClick={() => !isDisabled && setActiveTab(link.id)}
                  disabled={isDisabled}
                  className={`relative flex items-center px-5 py-2.5 rounded-full text-[11px] font-black uppercase tracking-wider transition-all duration-500
                      ${isActive 
                          ? `${link.color} shadow-sm` 
                          : 'text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-200'
                      }
                      ${isDisabled ? 'opacity-20 cursor-not-allowed' : 'cursor-pointer'}
                  `}
                >
                  {isActive && (
                    <motion.div 
                        layoutId="activeTabBg"
                        className={`absolute inset-0 ${link.bg} rounded-full border border-current opacity-20`}
                        transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                    />
                  )}

                  <span className="relative z-10 flex items-center gap-2.5">
                    <link.icon className={`w-4 h-4 transition-transform duration-300 ${isActive ? 'scale-110' : 'opacity-60'}`} />
                    {link.label}
                  </span>

                  {isActive && (
                    <motion.div 
                      layoutId="activeTabDot"
                      className={`nav-accent bg-current`}
                    />
                  )}
                </button>
              );
            })}
          </div>

          <div className="flex items-center">
             <motion.button 
                whileTap={{ scale: 0.9 }}
                onClick={onMenuClick}
                className="p-3.5 rounded-2xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 hover:bg-slate-50 dark:hover:bg-white/10 text-slate-700 dark:text-slate-200 transition-all shadow-sm"
             >
                <HamburgerMenuIcon className="w-6 h-6" />
             </motion.button>
          </div>
      </div>
    </header>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ImageUploader } from './ImageUploader.tsx';
import { ResultsDisplay } from './ResultsDisplay.tsx';
import { Spinner } from './Spinner.tsx';
import { PrescriptionData } from '../types.ts';
import { formatDate } from '../lib/utils.ts';
import { AnalyzeIcon } from './icons/AnalyzeIcon.tsx';

interface AnalyzeViewProps {
  imageFiles: File[];
  imageUrls: string[];
  prescriptionData: PrescriptionData | null;
  isLoading: boolean;
  error: string | null;
  history: PrescriptionData[];
  onAddImages: (files: File[]) => void;
  onRemoveImage: (index: number) => void;
  onClearQueue: () => void;
  onAnalyze: () => void;
  onVerify: () => void;
  onSelectHistory: (report: PrescriptionData) => void;
  onViewAll?: () => void;
  triggerHaptic: (type: any) => void;
}

const m = motion as any;

const NetworkStatusBanner = () => {
    const [isOnline, setIsOnline] = useState(navigator.onLine);

    useEffect(() => {
        const handleOnline = () => setIsOnline(true);
        const handleOffline = () => setIsOnline(false);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    if (isOnline) return null;

    return (
        <motion.div 
            initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }}
            className="w-full bg-rose-600 text-white py-2 px-4 flex items-center justify-center gap-2 text-xs font-black uppercase tracking-widest z-[60]"
        >
            <span className="material-symbols-outlined text-sm">cloud_off</span>
            Offline Mode: Clinical Sync and AI Analysis are disabled
        </motion.div>
    );
};

const CameraScanner = ({ onCapture, onClose }: { onCapture: (file: File) => void, onClose: () => void }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }, 
          audio: false 
        });
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) {
        console.warn("Rear camera failed, attempting fallback...", err);
        try {
            const s = await navigator.mediaDevices.getUserMedia({ video: true, audio: false });
            setStream(s);
            if (videoRef.current) videoRef.current.srcObject = s;
        } catch (fallbackErr) {
            alert("Camera access denied.");
            onClose();
        }
      }
    }
    startCamera();
    return () => {
      if (stream) stream.getTracks().forEach(t => t.stop());
    };
  }, []);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0);
        canvas.toBlob((blob) => {
          if (blob) {
            const file = new File([blob], `scan_${Date.now()}.jpg`, { type: 'image/jpeg' });
            onCapture(file);
          }
        }, 'image/jpeg', 0.95);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[120] bg-black flex flex-col items-center justify-center overflow-hidden">
      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
      <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
        <div className="w-[85%] max-w-md aspect-[3/4] rounded-3xl border-2 border-white/30 relative shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]">
          <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-primary rounded-tl-3xl" />
          <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-primary rounded-tr-3xl" />
          <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-primary rounded-bl-3xl" />
          <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-primary rounded-br-3xl" />
          <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-primary/30 animate-pulse shadow-[0_0_15px_rgba(13,215,242,0.5)]" />
        </div>
        <p className="mt-8 text-white font-bold text-sm uppercase tracking-widest drop-shadow-md">Align prescription in frame</p>
      </div>
      <div className="absolute bottom-0 left-0 right-0 p-10 bg-gradient-to-t from-black/80 to-transparent flex items-center justify-between px-16">
        <button onClick={onClose} className="p-4 rounded-full bg-white/10 text-white hover:bg-white/20 transition-colors pointer-events-auto">
          <span className="material-symbols-outlined text-3xl">close</span>
        </button>
        <button onClick={takePhoto} className="size-20 rounded-full border-4 border-white bg-white/20 p-1 pointer-events-auto transition-transform active:scale-90">
          <div className="size-full rounded-full bg-white shadow-xl" />
        </button>
        <div className="size-14" />
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

